sql:
SELECT description 
FROM industry_trends 
WHERE trend_id = 1;

SELECT AVG(median_price_change) AS median_price_change_average
FROM median_price_changes
WHERE industry_id = 0;

SELECT *
FROM industry_news
WHERE industry_id = 1;

external_knowledge:
- 'distinct list of investor names' means each investor is mentioned only once;
- 'transformed into lowercase' suggests standardizing the way investor names are written for consistency;
- 'seeds sprouting in a fertile garden' is a metaphor for the unique investors emerging from a rich dataset.

sql:
SELECT title, source, strftime('%Y', published_at) AS year
FROM industry_news
ORDER BY strftime('%Y', published_at);

SELECT companies.company_name, industries.sector
FROM companies
JOIN industries ON companies.industry_id = industries.industry_id;

SELECT AVG(barometer_value) AS average_barometer_value
FROM barometers
WHERE year = '2023' AND quarter = 'Q1';
